import{c as t,Q as o,j as a,m as i}from"./chunks/framework.CdiUUa3G.js";const p=JSON.parse('{"title":"ADR-045 — RTL strategy for Arabic locale","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-045.md","filePath":"adr/ADR-045.md"}'),r={name:"adr/ADR-045.md"};function l(n,e,s,c,d,u){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-045-—-rtl-strategy-for-arabic-locale" tabindex="-1">ADR-045 — RTL strategy for Arabic locale <a class="header-anchor" href="#adr-045-—-rtl-strategy-for-arabic-locale" aria-label="Permalink to &quot;ADR-045 — RTL strategy for Arabic locale&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-05-06 Supersedes in part · <code>docs/adr/ADR-032.md</code> (Wave 3 RTL deferred note) Scope · <code>ar</code> runtime direction handling</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Issue #38 adds Wave 3 locales including Arabic (<code>ar</code>), which requires right-to-left document flow. ADR-032 deferred the RTL strategy decision pending Wave 3 scheduling.</p><p>The app is SvelteKit SPA navigation with <code>?lang=</code> as locale source-of-truth. Direction must update both on first load and client-side route transitions.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Use a lightweight global document-attribute strategy:</p><ul><li>set <code>&lt;html lang=&quot;...&quot;&gt;</code> to the active locale code</li><li>set <code>&lt;html dir=&quot;rtl&quot;&gt;</code> only when locale is <code>ar</code></li><li>set <code>&lt;html dir=&quot;ltr&quot;&gt;</code> for all other locales</li></ul><p>Direction updates run in the existing locale runtime effect tied to URL <code>?lang=</code>.</p><p>No global CSS rewrite is performed in this rollout.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><ul><li>Minimal invasive change that aligns with existing locale resolution flow.</li><li>Works across all routes, including canvas-heavy views, without route-specific overrides.</li><li>Avoids risk and churn of immediate full migration to CSS logical properties.</li><li>Keeps room for progressive RTL hardening later if component-level issues emerge.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive:</p><ul><li>Arabic UI chrome mirrors via native browser bidi/layout behavior.</li><li>Runtime behavior stays consistent during in-app navigation.</li><li>Non-RTL locales remain unchanged (<code>ltr</code>).</li></ul><p>Negative:</p><ul><li>Components using physical left/right CSS may need targeted follow-up fixes.</li><li>This does not by itself guarantee perfect mirrored spacing in every legacy selector.</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Full logical-properties refactor now:</strong> highest long-term correctness, but too broad and risky for locale rollout scope.</li><li><strong>Separate <code>rtl.css</code> override sheet:</strong> can work, but adds maintenance burden and selector drift risk.</li><li><strong>Per-component conditional classes only:</strong> fragmented and error-prone compared with a single global source.</li></ul><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><ul><li>Extend locale utilities with RTL awareness (<code>ar</code> only in current set).</li><li>Sync <code>document.documentElement</code> <code>lang</code>/<code>dir</code> from the resolved URL locale on runtime updates.</li><li>Cover with Arabic e2e smoke that asserts RTL + locale persistence.</li></ul>',21)])])}const m=t(r,[["render",l]]);export{p as __pageData,m as default};
